// MARK: - Security Validator

final class UniversalLinkSecurityValidator {
    
    // Allowed domains for universal links
    private static let allowedDomains: Set<String> = [
        "myapp.com",
        "www.myapp.com"
    ]
    
    // Allowed URL schemes
    private static let allowedSchemes: Set<String> = [
        "https"
    ]
    
    // Allowed paths
    private static let allowedPaths: Set<String> = [
        "/promo"
    ]
    
    // Maximum parameter lengths to prevent buffer overflow attacks
    private static let maxPromoCodeLength = 50
    private static let maxDiscountValue = 100
    private static let minDiscountValue = 1
    
    // Promo code whitelist pattern: alphanumeric and hyphens only
    private static let promoCodePattern = "^[A-Za-z0-9\\-]{1,50}$"
    
    enum ValidationError: Error, LocalizedError {
        case invalidScheme
        case invalidDomain
        case invalidPath
        case missingParameters
        case invalidPromoCodeFormat
        case invalidDiscountValue
        case promoCodeTooLong
        case suspiciousInput
        case rateLimitExceeded
        
        var errorDescription: String? {
            switch self {
            case .invalidScheme:
                return "Only HTTPS links are accepted."
            case .invalidDomain:
                return "Link domain is not authorized."
            case .invalidPath:
                return "Invalid link path."
            case .missingParameters:
                return "Required parameters are missing."
            case .invalidPromoCodeFormat:
                return "Promo code contains invalid characters."
            case .invalidDiscountValue:
                return "Discount value is out of valid range."
            case .promoCodeTooLong:
                return "Promo code exceeds maximum length."
            case .suspiciousInput:
                return "Suspicious input detected."
            case .rateLimitExceeded:
                return "Too many attempts. Please try again later."
            }
        }
    }
    
    static func validateURL(_ url: URL) -> Result<(code: String, discount: Int), ValidationError> {
        // 1. Validate scheme (HTTPS only)
        guard let scheme = url.scheme?.lowercased(), allowedSchemes.contains(scheme) else {
            logSecurityEvent(event: "Invalid scheme", url: url)
            return .failure(.invalidScheme)
        }
        
        // 2. Validate domain
        guard let host = url.host?.lowercased(), allowedDomains.contains(host) else {
            logSecurityEvent(event: "Invalid domain", url: url)
            return .failure(.invalidDomain)
        }
        
        // 3. Validate path
        let path = url.path.lowercased()
        guard allowedPaths.contains(path) else {
            logSecurityEvent(event: "Invalid path", url: url)
            return .failure(.invalidPath)
        }
        
        // 4. Extract and validate parameters
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true),
              let queryItems = components.queryItems else {
            return .failure(.missingParameters)
        }
        
        // 5. Check for unexpected/extra parameters (defense against parameter pollution)
        let allowedParameterNames: Set<String> = ["code", "discount"]
        let receivedParameterNames = Set(queryItems.map { $0.name })
        let unexpectedParams = receivedParameterNames.subtracting(allowedParameterNames)
        if !unexpectedParams.isEmpty {
            logSecurityEvent(event: "Unexpected parameters: \(unexpectedParams)", url: url)
            return .failure(.suspiciousInput)
        }
        
        // 6. Extract promo code
        guard let promoCode = queryItems.first(where: { $0.name == "code" })?.value,
              !promoCode.isEmpty else {
            return .failure(.missingParameters)
        }
        
        // 7. Validate promo code length
        guard promoCode.count <= maxPromoCodeLength else {
            logSecurityEvent(event: "Promo code too long", url: url)
            return .failure(.promoCodeTooLong)
        }
        
        // 8. Validate promo code format (prevent injection attacks)
        guard isValidPromoCodeFormat(promoCode) else {
            logSecurityEvent(event: "Invalid promo code format", url: url)
            return .failure(.invalidPromoCodeFormat)
        }
        
        // 9. Check for injection patterns
        guard !containsInjectionPatterns(promoCode) else {
            logSecurityEvent(event: "Injection pattern detected in promo code", url: url)
            return .failure(.suspiciousInput)
        }
        
        // 10. Extract and validate discount
        guard let discountString = queryItems.first(where: { $0.name == "discount" })?.value,
              let discount = Int(discountString) else {
            return .failure(.invalidDiscountValue)
        }
        
        guard discount >= minDiscountValue && discount <= maxDiscountValue else {
            logSecurityEvent(event: "Discount out of range: \(discount)", url: url)
            return .failure(.invalidDiscountValue)
        }
        
        // Sanitize the promo code
        let sanitizedCode = sanitizeInput(promoCode)
        
        return .success((code: sanitizedCode, discount: discount))
    }
    
    private static func isValidPromoCodeFormat(_ code: String) -> Bool {
        guard let regex = try? NSRegularExpression(pattern: promoCodePattern) else {
            return false
        }
        let range = NSRange(code.startIndex..., in: code)
        return regex.firstMatch(in: code, range: range) != nil
    }
    
    private static func containsInjectionPatterns(_ input: String) -> Bool {
        let dangerousPatterns = [
            "<script", "javascript:", "data:", "vbscript:",
            "onclick", "onerror", "onload",
            "SELECT ", "INSERT ", "UPDATE ", "DELETE ", "DROP ",
            "UNION ", "OR 1=1", "' OR '", "\" OR \"",
            "../", "..\\", "%00", "%0d", "%0a",
            "eval(", "exec(", "system("
        ]
        
        let lowercasedInput = input.lowercased()
        return dangerousPatterns.contains { lowercasedInput.contains($0.lowercased()) }
    }
    
    private static func sanitizeInput(_ input: String) -> String {
        // Remove any characters that aren't alphanumeric or hyphens
        return input.filter { $0.isLetter || $0.isNumber || $0 == "-" }
    }
    
    private static func logSecurityEvent(event: String, url: URL) {
        let sanitizedURL = url.absoluteString.prefix(200)
        let timestamp = ISO8601DateFormatter().string(from: Date())
        print("⚠️ [SECURITY] [\(timestamp)] \(event) | URL: \(sanitizedURL)")
        // In production, send to security monitoring service
    }
}

// MARK: - Rate Limiter

final class RateLimiter {
    static let shared = RateLimiter()
    
    private var attempts: [String: [Date]] = [:]
    private let maxAttempts = 5
    private let windowSeconds: TimeInterval = 300 // 5 minutes
    private let queue = DispatchQueue(label: "com.myapp.ratelimiter", attributes: .concurrent)
    
    private init() {}
    
    func isAllowed(identifier: String) -> Bool {
        var allowed = false
        queue.sync(flags: .barrier) {
            let now = Date()
            let windowStart = now.addingTimeInterval(-windowSeconds)
            
            // Clean old entries
            attempts[identifier] = (attempts[identifier] ?? []).filter { $0 > windowStart }
            
            let currentAttempts = attempts[identifier]?.count ?? 0
            if currentAttempts < maxAttempts {
                attempts[identifier, default: []].append(now)
                allowed = true
            }
        }
        return allowed
    }
    
    func reset(identifier: String) {
        queue.sync(flags: .barrier) {
            attempts.removeValue(forKey: identifier)
        }
    }
}

