                    completion(.failure(PromoError.promoNotFound))
                case 410:
                    completion(.failure(PromoError.promoExpired))
                case 429:
                    completion(.failure(PromoError.rateLimited))
                default:
                    completion(.failure(PromoError.serverError(httpResponse.statusCode)))
