                    return
                }
                
                completion(.success(promo))
            } catch {
                completion(.failure(error))
            }
        }
        task.resume()
    }
    
    func applyPromoToAccount(userId: String, promo: PromoCode, completion: @escaping (Result<PromoApplicationResult, Error>) -> Void) {
