                message: "Promo code \(promo.code) applied! You got \(promo.discountPercentage)% off.",
                appliedDiscount: promo.discountPercentage,
                promoCode: promo.code
            )
            completion(.success(result))
        }
        task.resume()
    }
    
    private func generateHMAC(data: Data) -> String? {
        guard let secret = KeychainManager.shared.getAPISecret() else { return nil }
        let key = SymmetricKey(data: Data(secret.utf8))
        let signature = HMAC<SHA256>.authenticationCode(for: data, using: key)
        return Data(signature).base64EncodedString()
    }
    
    enum PromoError: Error, LocalizedError {
        case invalidURL
        case invalidResponse
        case noData
        case promoNotFound
        case promoExpired
        case rateLimited
        case serverError(Int)
        case discountMismatch
        case applicationFailed
        case userNotAuthenticated
        
        var errorDescription: String? {
            switch self {
            case .invalidURL: return "Invalid request URL."
            case .invalidResponse: return "Invalid server response."
            case .noData: return "No data received."
            case .promoNotFound: return "Promo code not found."
            case .promoExpired: return "This promo code has expired."
            case .rateLimited: return "Too many requests. Please try again later."
            case .serverError(let code): return "Server error (\(code))."
            case .discountMismatch: return "Discount verification failed."
            case .applicationFailed: return "Failed to apply promo code."
            case .userNotAuthenticated: return "Please log in to apply promo codes."
            }
        }
    }
}

// MARK: - SSL Pinning Delegate

final class SSLPinningDelegate: NSObject, URLSessionDelegate {
    
    // SHA256 hash of the server's public key (replace with actual pin)
    private let pinnedPublicKeyHashes: Set<String> = [
        "BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB="  // Replace with actual hash
    ]
    
    func urlSession(_ session: URLSession, didReceive challenge: URLAuthenticationChallenge, completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let serverTrust = challenge.protectionSpace.serverTrust,
              challenge.protectionSpace.host == "api.myapp.com" else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // Evaluate server trust
        var error: CFError?
        let isValid = SecTrustEvaluateWithError(serverTrust, &error)
        
        guard isValid else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // In production, implement full public key pinning here
        let credential = URLCredential(trust: serverTrust)
        completionHandler(.useCredential, credential)
    }
}

// MARK: - Keychain Manager

final class KeychainManager {
    static let shared = KeychainManager()
    
    private init() {}
    
    func getAuthToken() -> String? {
        return getKeychainItem(key: "auth_token")
    }
    
    func getUserId() -> String? {
        return getKeychainItem(key: "user_id")
    }
    
    func getAPISecret() -> String? {
        return getKeychainItem(key: "api_secret")
    }
    
    func saveAuthToken(_ token: String) {
        saveKeychainItem(key: "auth_token", value: token)
    }
    
    private func getKeychainItem(key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecAttrService as String: Bundle.main.bundleIdentifier ?? "com.myapp",
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else {
            return nil
        }
        
        return String(data: data, encoding: .utf8)
    }
    
    private func saveKeychainItem(key: String, value: String) {
        guard let data = value.data(using: .utf8) else { return }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecAttrService as String: Bundle.main.bundleIdentifier ?? "com.myapp",
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        SecItemDelete(query as CFDictionary)
        SecItemAdd(query as CFDictionary, nil)
    }
}

// MARK: - Promo Link Handler

final class PromoLinkHandler {
    
    static let shared = PromoLinkHandler()
    
    private let promoService: PromoServiceProtocol
    private let rateLimiter = RateLimiter.shared
    
    // Track processed links to prevent replay attacks
    private var processedLinks: Set<String> = []
    private let processedLinksQueue = DispatchQueue(label: "com.myapp.processedlinks", attributes: .concurrent)
    
    // Pending promo for unauthenticated users
    private(set) var pendingPromo: (code: String, discount: Int)?
    
    init(promoService: PromoServiceProtocol = PromoService.shared) {
        self.promoService = promoService
    }
    
    func handleUniversalLink(_ url: URL, completion: @escaping (PromoApplicationResult) -> Void) {
        // 1. Rate limiting
        let deviceId = UIDevice.current.identifierForVendor?.uuidString ?? "unknown"
        guard rateLimiter.isAllowed(identifier: deviceId) else {
            let result = PromoApplicationResult(
                success: false,
                message: "Too many promo attempts. Please try again later.",
                appliedDiscount: nil,
                promoCode: nil
            )
            completion(result)
            return
        }
        
        // 2. Replay attack prevention
        let linkFingerprint = generateLinkFingerprint(url)
        var isReplay = false
        processedLinksQueue.sync {
            isReplay = processedLinks.contains(linkFingerprint)
        }
        
        if isReplay {
            let result = PromoApplicationResult(
                success: false,
                message: "This promo link has already been used.",
                appliedDiscount: nil,
                promoCode: nil
            )
            completion(result)
            return
        }
        
        // 3. Validate URL security
        let validationResult = UniversalLinkSecurityValidator.validateURL(url)
        
        switch validationResult {
        case .failure(let error):
            let result = PromoApplicationResult(
                success: false,
                message: error.localizedDescription,
                appliedDiscount: nil,
                promoCode: nil
            )
            completion(result)
            
        case .success(let params):
            // Mark link as processed
            processedLinksQueue.sync(flags: .barrier) {
                processedLinks.insert(linkFingerprint)
            }
            
            // 4. Check if user is authenticated
            guard let userId = KeychainManager.shared.getUserId() else {
                // Store pending promo for after login
                pendingPromo = (code: params.code, discount: params.discount)
                let result = PromoApplicationResult(
                    success: false,
                    message: "Please log in to apply your promo code \(params.code) for \(params.discount)% off!",
                    appliedDiscount: nil,
                    promoCode: params.code
                )
                completion(result)
                return
            }
            
            // 5. Server-side validation (NEVER trust client-side discount values)
            promoService.validatePromoCode(params.code, discount: params.discount) { [weak self] validateResult in
                switch validateResult {
                case .failure(let error):
                    let result = PromoApplicationResult(
                        success: false,
                        message: error.localizedDescription,
                        appliedDiscount: nil,
                        promoCode: params.code
                    )
                    DispatchQueue.main.async { completion(result) }
                    
                case .success(let promo):
                    // 6. Apply to account
                    self?.promoService.applyPromoToAccount(userId: userId, promo: promo) { applyResult in
                        switch applyResult {
                        case .failure(let error):
                            let result = PromoApplicationResult(
                                success: false,
                                message: error.localizedDescription,
                                appliedDiscount: nil,
                                promoCode: params.code
                            )
                            DispatchQueue.main.async { completion(result) }
                            
                        case .success(let result):
                            self?.pendingPromo = nil
                            DispatchQueue.main.async { completion(result) }
                        }
                    }
                }
            }
        }
    }
    
    func applyPendingPromo(completion: @escaping (PromoApplicationResult) -> Void) {
        guard let pending = pendingPromo else {
            let result = PromoApplicationResult(
                success: false,
                message: "No pending promo code.",
                appliedDiscount: nil,
                promoCode: nil
            )
            completion(result)
            return
        }
        
        guard let userId = KeychainManager.shared.getUserId() else {
            let result = PromoApplicationResult(
                success: false,
                message: "Please log in first.",
                appliedDiscount: nil,
                promoCode: pending.code
            )
            completion(result)
            return
        }
        
        promoService.validatePromoCode(pending.code, discount: pending.discount) { [weak self] validateResult in
            switch validateResult {
            case .failure(let error):
                let result = PromoApplicationResult(
                    success: false,
                    message: error.localizedDescription,
                    appliedDiscount: nil,
                    promoCode: pending.code
                )
                DispatchQueue.main.async { completion(result) }
                
            case .success(let promo):
                self?.promoService.applyPromoToAccount(userId: userId, promo: promo) { applyResult in
                    switch applyResult {
                    case .failure(let error):
                        let result = PromoApplicationResult(
                            success: false,
                            message: error.localizedDescription,
                            appliedDiscount: nil,
                            promoCode: pending.code
                        )
                        DispatchQueue.main.async { completion(result) }
                        
                    case .success(let result):
                        self?.pendingPromo = nil
                        DispatchQueue.main.async { completion(result) }
                    }
                }
            }
        }
    }
    
    func clearProcessedLinks() {
        processedLinksQueue.sync(flags: .barrier) {
            processedLinks.removeAll()
        }
    }
    
    private func generateLinkFingerprint(_ url: URL) -> String {
        let data = Data(url.absoluteString.utf8)
        let hash = SHA256.hash(data: data)
        return hash.compactMap { String(format: "%02x", $0) }.joined()
    }
}

