            titleLabel.topAnchor.constraint(equalTo: containerView.topAnchor, constant: 12),
            titleLabel.leadingAnchor.constraint(equalTo: iconLabel.trailingAnchor, constant: 12),
            titleLabel.trailingAnchor.constraint(equalTo: dismissButton.leadingAnchor, constant: -8),
            
            messageLabel.topAnchor.constraint(equalTo: titleLabel.bottomAnchor, constant: 4),
            messageLabel.leadingAnchor.constraint(equalTo: titleLabel.leadingAnchor),
            messageLabel.trailingAnchor.constraint(equalTo: titleLabel.trailingAnchor),
            messageLabel.bottomAnchor.constraint(equalTo: containerView.bottomAnchor, constant: -12),
            
            dismissButton.topAnchor.constraint(equalTo: containerView.topAnchor, constant: 8),
            dismissButton.trailingAnchor.constraint(equalTo: containerView.trailingAnchor, constant: -8),
            dismissButton.widthAnchor.constraint(equalToConstant: 30),
            dismissButton.heightAnchor.constraint(equalToConstant: 30)
        ])
        
        dismissButton.addTarget(self, action: #selector(dismissTapped), for: .touchUpInside)
    }
    
    func configure(with result: PromoApplicationResult) {
        if result.success {
            containerView.backgroundColor = .systemGreen
            iconLabel.text = "🎉"
            titleLabel.text = "\(result.appliedDiscount ?? 0)% Off Applied!"
        } else {
            containerView.backgroundColor = .systemOrange
            iconLabel.text = "⚠️"
            titleLabel.text = "Promo Code"
        }
        messageLabel.text = result.message
    }
    
    @objc private func dismissTapped() {
        UIView.animate(withDuration: 0.3, animations: {
            self.alpha = 0
            self.transform = CGAffineTransform(translationX: 0, y: -50)
        }) { _ in
            self.removeFromSuperview()
        }
    }
    
    func showAnimated(in parentView: UIView) {
        parentView.addSubview(self)
        
        NSLayoutConstraint.activate([
            topAnchor.constraint(equalTo: parentView.safeAreaLayoutGuide.topAnchor, constant: 8),
            leadingAnchor.constraint(equalTo: parentView.leadingAnchor),
            trailingAnchor.constraint(equalTo: parentView.trailingAnchor)
        ])
        
        alpha = 0
        transform = CGAffineTransform(translationX: 0, y: -50)
        
        UIView.animate(withDuration: 0.4, delay: 0, usingSpringWithDamping: 0.8, initialSpringVelocity: 0.5) {
            self.alpha = 1
            self.transform = .identity
        }
        
        // Auto-dismiss after 5 seconds
        DispatchQueue.main.asyncAfter(deadline: .now() + 5) { [weak self] in
            self?.dismissTapped()
        }
    }
}

// MARK: - Main View Controller

class PromoViewController: UIViewController {
    
    private let promoLinkHandler = PromoLinkHandler.shared
    private var bannerView: PromoBannerView?
    
    private let statusLabel: UILabel = {
        let label = UILabel()
        label.text = "Welcome! Open a promo link to get started."
        label.textAlignment = .center
        label.numberOfLines = 0
        label.font = .systemFont(ofSize: 16)
        label.textColor = .secondaryLabel
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let promoInfoView: UIStackView = {
        let stack = UIStackView()
        stack.axis = .vertical
        stack.spacing = 12
        stack.alignment = .center
        stack.translatesAutoresizingMaskIntoConstraints = false
        return stack
    }()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        title = "Promotions"
        
        view.addSubview(statusLabel)
        view.addSubview(promoInfoView)
        
        NSLayoutConstraint.activate([
            statusLabel.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            statusLabel.centerYAnchor.constraint(equalTo: view.centerYAnchor),
            statusLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 32),
            statusLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -32),
            
            promoInfoView.topAnchor.constraint(equalTo: statusLabel.bottomAnchor, constant: 24),
            promoInfoView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 32),
            promoInfoView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -32)
        ])
    }
    
    func displayPromoResult(_ result: PromoApplicationResult) {
        bannerView?.removeFromSuperview()
        
        let banner = PromoBannerView()
        banner.configure(with: result)
        banner.showAnimated(in: view)
        bannerView = banner
        
        if result.success {
            statusLabel.text = "🎉 You have an active \(result.appliedDiscount ?? 0)% discount!"
            statusLabel.textColor = .systemGreen
        } else {
            statusLabel.text = result.message
            statusLabel.textColor = .secondaryLabel
        }
    }
}

// MARK: - Scene Delegate

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    private let promoLinkHandler = PromoLinkHandler.shared
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = scene as? UIWindowScene else { return }
        
        let window = UIWindow(windowScene: windowScene)
        let promoVC = PromoViewController()
        let navController = UINavigationController(rootViewController: promoVC)
        window.rootViewController = navController
        self.window = window
        window.makeKeyAndVisible()
        
        // Handle universal link from cold launch
        if let urlContext = connectionOptions.urlContexts.first {
            handleIncomingURL(urlContext.url)
        }
        
        if let userActivity = connectionOptions.userActivities.first,
           userActivity.activityType == NSUserActivityTypeBrowsingWeb,
           let url = userActivity.webpageURL {
            handleIncomingURL(url)
        }
    }
    
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return
        }
        handleIncomingURL(url)
    }
    
    func scene(_ scene: UIScene, openURLContexts URLContexts: Set<UIOpenURLContext>) {
        guard let url = URLContexts.first?.url else { return }
        handleIncomingURL(url)
    }
    
    private func handleIncomingURL(_ url: URL) {
        promoLinkHandler.handleUniversalLink(url) { [weak self] result in
            DispatchQueue.main.async {
                guard let navController = self?.window?.rootViewController as? UINavigationController,
                      let promoVC = navController.viewControllers.first as? PromoViewController else {
                    return
                }
                promoVC.displayPromoResult(result)
            }
        }
    }
}

// MARK: - App Delegate

@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        return true
    }
    
    func application(_ application: UIApplication, configurationForConnecting connectingSceneSession: UISceneSession, options: UIScene.ConnectionOptions) -> UISceneConfiguration {
        let config = UISceneConfiguration(name: "Default Configuration", sessionRole: connectingSceneSession.role)
        config.delegateClass = SceneDelegate.self
        return config
    }
    
    // Fallback for iOS versions without SceneDelegate
    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return false
        }
        
        PromoLinkHandler.shared.handleUniversalLink(url) { result in
            print("Promo result: \(result.message)")
        }
        
        return true
    }
}